import numpy as np

def time_decayed_preferences(
    interactions: list[tuple[int, float, float]],
    t_now: float,
    decay: float = 0.1,
    k: int = 5
) -> list[int]:
    scores: dict[int, float] = {}
    for item_id, t, rating in interactions:
        weight = np.exp(-decay * (t_now - t))
        scores[item_id] = scores.get(item_id, 0.0) + rating * weight
    sorted_items = sorted(scores.keys(), key=lambda x: -scores[x])
    return sorted_items[:k]
